<template>
  <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>SERVICIOS EN LA CARRERA</h1>
          </div>

          <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
                <h5>
                  SERVICIOS
                </h5>
        
        </div>
      </div>
    </div>
  </div>

  <!-- ==============================================
    ** Blog **
    =================================================== -->
  <div class="container blog-wrapper padding-lg">
    <div v-if="Servicios.length == 0">
      <h1>NO HAY SERVICIOS</h1>
    </div>

    <div v-for="(serv, id_serv) of Servicios" :key="id_serv" v-show="(pag - 1) * NUM_RESULTS <= id_serv &&
      pag * NUM_RESULTS > id_serv
      ">
      <!-- Start Left Column -->
      <div class="col-sm-8 blog-left">
        <ul class="blog-listing">
          <li>
            <!-- <router-link
                      :to="'/detalleServicio/' + serv.serv_id"
                      @click="$store.commit('clickLink')"
                    > -->
            <img style="width: 750px; height: 270px" 
            :src="url_api + '/Carrera/Servicios/' + serv.serv_imagen" 
            class="img-responsive" alt="" />
            <!-- </router-link> -->

         
            <br />
            <div class="left-aligned">
              <ul class="post-detail">
                <li>
                  <span class="icon-date-icon ico"></span><span class="bold">{{ dmy(serv.serv_registro) }}</span>
                </li>
                <li>
                  <i class="fa fa-phone"></i>
                  <span class="bold">{{ serv.serv_nro_celular }}</span>
                </li>
                <li><span class="label">SERVICIOS</span></li>
              </ul>

              <h2>

                <router-link
                        :to="'/detalleServicio/' + serv.serv_id"
                        @click="$store.commit('clickLink')"
                      >
                      {{ serv.serv_nombre }}
                      </router-link>
              </h2>
              <!-- <p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting...</p> -->

              <!-- <router-link :to="'/detallePublicacion/' + pub.publicaciones_id" @click="$store.commit('clickLink')"
                class="read-more"><span class="icon-play-icon"></span>
                Leer más
              </router-link> -->
            </div>
          </li>
        </ul>

        <div class="text-center">
          <ul class="pagination blue">
            <li class="pagination-arrow disable">
              <a href="#" aria-label="Previous" @click.prevent="pag != 1 ? (pag -= 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-left" aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>

            <li v-for="(i, index) of pager" :key="index">
              <a href="#" :class="[i == pag ? 'active' : '']" @click.prevent="pag = i">
                {{ i }}
              </a>
            </li>

            <li>
              <a href="#" aria-label="Next" @click.prevent="pag != pager ? (pag += 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-right" aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>
          </ul>
        </div>





      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">
        
        <SidebarCustom> </SidebarCustom>
      </div>
      <!-- End Right Column -->
    </div>
  </div>
</template>

<style scoped>
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>

import SidebarCustom from "@/components/SidebarCustom.vue";
import { mapState } from "vuex";
export default {
  name: "ServiciosView",
  data() {
    return {
      Servicios: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,

      //------
      tipo: "",
      Convocatorias: [],
    };
  },
  components: {
    SidebarCustom,
  },
  computed: {
    ...mapState(["url_api", "getter"]), //===getter
  },
  methods: {
    async getServiciosAll() {
      try {
        let res = await this.axios.get(
          "/api/ServicioAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Servicios = [];
        res.data.forEach((servicio) => {
          if (servicio.serv_active == "1") {
            this.Servicios.push(servicio);
          }
        });
        this.pager = this.Servicios.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    async getTipoConv(tipo_conv) { //===
      try {
        let res = await this.axios.get("/api/Tipoconvocatorias/" + tipo_conv);
        this.tipo = res.data.Descripcion.tipo_conv_comun_titulo;
        this.getConvocatorias();
      } catch (error) {
        console.log(error);
      }
    },
    async getConvocatorias() { //===
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Convocatorias = [];
        res.data.forEach((cca) => {
          if (
            cca.con_estado == "1" &&
            cca.tipo_conv_comun.tipo_conv_comun_titulo == this.tipo
          ) {
            this.Convocatorias.push(cca);
          }
        });
        this.pager = this.Convocatorias.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() { //===
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[parseInt(fechaArray[1]) - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Servicios.forEach((serv) => {
          if (
            serv.serv_nombre.toUpperCase().includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(serv);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getServiciosAll();

    //=====
    this.getTipoConv(this.$route.params.tipo_conv);
  },
  updated() {//=======
    if (this.getter) {
      this.$store.commit("loadOn");
      this.getTipoConv(this.$route.params.tipo_conv);
      this.$store.state.getter = false;
    }
  },
  created() {
    this.$store.commit("loadOn");
    this.getServiciosAll();

    this.getTipoConv(this.$route.params.tipo_conv);//=======
  },
};
</script>